import React from 'react';
import { AppMode } from '../types';
import { LogIcon } from './icons/LogIcon';
import { WrenchIcon } from './icons/WrenchIcon';
import { ChatIcon } from './icons/ChatIcon';
import { CalculatorIcon } from './icons/CalculatorIcon';
import { BlueprintIcon } from './icons/BlueprintIcon';
import { ExportIcon } from './icons/ExportIcon';

interface TabsProps {
  activeMode: AppMode;
  setActiveMode: (mode: AppMode) => void;
}

const Tabs: React.FC<TabsProps> = ({ activeMode, setActiveMode }) => {
  const tabs = [
    { mode: AppMode.Recovery, label: 'Active Recovery', icon: <WrenchIcon className="h-5 w-5 mr-2" /> },
    { mode: AppMode.Log, label: 'Log', icon: <LogIcon className="h-5 w-5 mr-2" /> },
    { mode: AppMode.Training, label: 'Training', icon: <ChatIcon className="h-5 w-5 mr-2" /> },
    { mode: AppMode.DensityCalculator, label: 'Density', icon: <CalculatorIcon className="h-5 w-5 mr-2" /> },
    { mode: AppMode.Blueprints, label: 'Blueprints', icon: <BlueprintIcon className="h-5 w-5 mr-2" /> },
    { mode: AppMode.Export, label: 'Export PDF', icon: <ExportIcon className="h-5 w-5 mr-2" /> },
  ];

  const getTabClass = (mode: AppMode) => {
    const baseClass = "flex-1 text-center py-3 px-2 font-semibold text-xs md:text-sm rounded-t-lg transition-colors duration-300 ease-in-out flex items-center justify-center cursor-pointer";
    if (mode === activeMode) {
      return `${baseClass} bg-dark-card text-brand-blue border-b-2 border-brand-blue`;
    }
    return `${baseClass} bg-transparent text-gray-400 hover:bg-dark-input hover:text-white`;
  };

  return (
    <nav className="flex border-b border-dark-border flex-shrink-0 overflow-x-auto no-scrollbar">
      {tabs.map(tab => (
        <button key={tab.mode} onClick={() => setActiveMode(tab.mode)} className={getTabClass(tab.mode)}>
          {tab.icon}
          <span className="hidden sm:inline">{tab.label}</span>
        </button>
      ))}
    </nav>
  );
};

export default Tabs;

import React, { useState } from 'react';
import { AppMode, ChatMessage, LogEntry, User, TroubleshootingScenario, Blueprint, TrainingCourse, System } from '../types';
import Tabs from './Tabs';
import TroubleshootingLog from './TroubleshootingLog';
import ActiveRecovery from './ActiveRecovery';
import TrainingMode from './TrainingMode';
import DensityCalculator from './DensityCalculator';
import Blueprints from './Blueprints';
import ExportCenter from './ExportCenter';

interface ChatInterfaceProps {
    user: Omit<User, 'password'>;
    logEntries: LogEntry[];
    addLogEntry: (entry: Omit<LogEntry, 'id' | 'timestamp' | 'author'>) => void;
    updateLogEntry: (updatedEntry: LogEntry) => void;
    deleteLogEntry: (id: string) => void;
    chatHistory: ChatMessage[];
    setChatHistory: React.Dispatch<React.SetStateAction<ChatMessage[]>>;
    troubleshootingScenarios: TroubleshootingScenario[];
    addTroubleshootingScenario: (scenario: Omit<TroubleshootingScenario, 'id'>) => void;
    trainingCourses: TrainingCourse[];
    addTrainingCourse: (course: Omit<TrainingCourse, 'id'>) => TrainingCourse;
    blueprints: { megajet: Blueprint[], grassilli: Blueprint[] };
    addBlueprint: (blueprint: Omit<Blueprint, 'id'>, system: System) => void;
    deleteBlueprint: (id: string, system: System) => void;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
    user, 
    logEntries, 
    addLogEntry, 
    updateLogEntry, 
    deleteLogEntry,
    chatHistory,
    setChatHistory,
    troubleshootingScenarios,
    addTroubleshootingScenario,
    trainingCourses,
    addTrainingCourse,
    blueprints,
    addBlueprint,
    deleteBlueprint
}) => {
    const [activeMode, setActiveMode] = useState<AppMode>(AppMode.Recovery);

    const renderContent = () => {
        switch (activeMode) {
            case AppMode.Log:
                return <TroubleshootingLog 
                            user={user} 
                            logEntries={logEntries} 
                            addLogEntry={addLogEntry} 
                            updateLogEntry={updateLogEntry}
                            deleteLogEntry={deleteLogEntry}
                        />;
            case AppMode.Recovery:
                return <ActiveRecovery 
                            user={user} 
                            addLogEntry={addLogEntry} 
                            messages={chatHistory}
                            setMessages={setChatHistory}
                        />;
            case AppMode.Training:
                return <TrainingMode 
                            user={user} 
                            troubleshootingScenarios={troubleshootingScenarios}
                            addTroubleshootingScenario={addTroubleshootingScenario}
                            trainingCourses={trainingCourses}
                            addTrainingCourse={addTrainingCourse}
                        />;
            case AppMode.DensityCalculator:
                return <DensityCalculator />;
            case AppMode.Blueprints:
                return <Blueprints blueprints={blueprints} addBlueprint={addBlueprint} deleteBlueprint={deleteBlueprint} />;
            case AppMode.Export:
                return <ExportCenter logEntries={logEntries} trainingCourses={trainingCourses} blueprints={blueprints} />;
            default:
                return <ActiveRecovery 
                            user={user} 
                            addLogEntry={addLogEntry} 
                            messages={chatHistory}
                            setMessages={setChatHistory}
                        />;
        }
    };

    return (
        <div className="flex-1 flex flex-col bg-dark-bg min-h-0">
           <Tabs activeMode={activeMode} setActiveMode={setActiveMode} />
           <div className="flex-1 p-4 overflow-y-auto">
             {renderContent()}
           </div>
        </div>
    );
};

export default ChatInterface;

import React, { useState } from 'react';
import { LogEntry, TrainingCourse, Blueprint } from '../types';
import { PECOFOODS_KNOWLEDGE_BASE } from '../constants/megajetKnowledge';
import { ExportIcon } from './icons/ExportIcon';
import { CheckIcon } from './icons/CheckIcon';
import { GoogleGenAI } from '@google/genai';
import { CogIcon } from './icons/CogIcon';

interface ExportCenterProps {
    logEntries: LogEntry[];
    trainingCourses: TrainingCourse[];
    blueprints: { megajet: Blueprint[], grassilli: Blueprint[] };
}

const ExportCenter: React.FC<ExportCenterProps> = ({ logEntries, trainingCourses, blueprints }) => {
    const [aiSummary, setAiSummary] = useState<string | null>(null);
    const [isGenerating, setIsGenerating] = useState(false);

    const handlePrint = () => {
        window.print();
    };

    const generateAISummary = async () => {
        setIsGenerating(true);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const recentLogs = logEntries.slice(0, 10).map(l => `- ${l.issue}: ${l.recoverySteps.substring(0, 100)}`).join('\n');
            const prompt = `Based on these recent poultry processing troubleshooting logs, generate a concise "Executive Engineering Summary" (max 250 words). Identify any recurring trends, critical risks, and recommended preventative maintenance actions. Format as professional markdown.

            LOGS:
            ${recentLogs}`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
            });
            setAiSummary(response.text || "No summary generated.");
        } catch (error) {
            console.error("Failed to generate summary", error);
            setAiSummary("Failed to generate AI summary. Proceeding with standard report.");
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div className="space-y-6 animate-fade-in pb-20">
            <style>{`
                @media print {
                    body { background: white !important; color: black !important; }
                    .no-print { display: none !important; }
                    .print-only { display: block !important; }
                    .page-break { page-break-before: always; }
                    .bg-dark-card, .bg-dark-input, .bg-dark-bg { background: white !important; color: black !important; border: 1px solid #ccc !important; }
                    header, nav { display: none !important; }
                    #root { height: auto !important; overflow: visible !important; }
                    main { height: auto !important; overflow: visible !important; display: block !important; }
                    .printable-doc { max-width: 100% !important; padding: 0 !important; }
                }
            `}</style>

            <div className="no-print bg-dark-card p-6 rounded-lg border border-dark-border mb-8">
                <h2 className="text-2xl font-bold text-brand-green mb-4 flex items-center">
                    <ExportIcon className="h-7 w-7 mr-3" />
                    Knowledge Export Center
                </h2>
                <p className="text-gray-400 mb-6">
                    Compile all gathered intelligence into a professional document. You can include an AI-generated executive summary of recent incidents before printing to PDF.
                </p>
                <div className="flex flex-wrap gap-4">
                    <button 
                        onClick={generateAISummary}
                        disabled={isGenerating}
                        className="bg-brand-blue hover:bg-blue-600 text-white font-bold py-2 px-6 rounded-lg flex items-center transition-colors disabled:opacity-50"
                    >
                        {isGenerating ? <CogIcon className="h-5 w-5 mr-2 animate-spin" /> : <CogIcon className="h-5 w-5 mr-2" />}
                        {aiSummary ? 'Regenerate AI Summary' : 'Generate AI Summary'}
                    </button>
                    <button 
                        onClick={handlePrint}
                        className="bg-brand-green hover:bg-green-600 text-white font-bold py-2 px-6 rounded-lg flex items-center transition-colors"
                    >
                        <CheckIcon className="h-5 w-5 mr-2" />
                        Print to PDF
                    </button>
                </div>
            </div>

            {/* The Actual Document Layout */}
            <div className="printable-doc bg-dark-card p-8 rounded-lg border border-dark-border shadow-2xl space-y-12">
                {/* Cover Page */}
                <div className="text-center py-20 border-b-4 border-brand-blue">
                    <h1 className="text-5xl font-black text-white uppercase tracking-tighter mb-4">
                        PecoFoods Pochanatas
                    </h1>
                    <h2 className="text-2xl font-bold text-brand-blue uppercase mb-8">
                        Troubleshooting & Knowledge Command Center Report
                    </h2>
                    <div className="text-gray-400 space-y-2">
                        <p>Generated on: {new Date().toLocaleDateString()} {new Date().toLocaleTimeString()}</p>
                        <p>Document Class: Restricted / Industrial Maintenance</p>
                        <p>System Status: Online</p>
                    </div>
                </div>

                {/* AI Executive Summary Section */}
                {aiSummary && (
                    <div className="bg-brand-blue/10 p-6 rounded-lg border-l-4 border-brand-blue">
                        <h3 className="text-xl font-bold text-brand-blue mb-4">I. AI Executive Summary (Recent Incidents)</h3>
                        <div className="prose prose-invert max-w-none text-gray-300 whitespace-pre-wrap">
                            {aiSummary}
                        </div>
                    </div>
                )}

                {/* Knowledge Base Section */}
                <div>
                    <h3 className="text-xl font-bold text-brand-blue mb-6 border-b border-dark-border pb-2">II. Core Knowledge Base</h3>
                    <div className="space-y-8">
                        {PECOFOODS_KNOWLEDGE_BASE.filter(kb => kb.type === 'program' || kb.type === 'troubleshooting').map((item: any) => (
                            <div key={item.id} className="p-4 bg-dark-input/50 rounded-lg border border-dark-border">
                                <h4 className="font-bold text-brand-green text-lg mb-2">{item.title || item.program_name}</h4>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                                    {item.details && (
                                        <div className="space-y-1">
                                            <p className="text-gray-500 font-semibold uppercase">Specifications:</p>
                                            <p className="text-gray-300">Target Weight: {item.details.target_weight_g || item.details.in_house_target_weight_g}g</p>
                                            <p className="text-gray-300">Thickness: {item.details.target_thickness_mm || 'Vision Optimized'}</p>
                                        </div>
                                    )}
                                    {item.critical_recovery_steps && (
                                        <div className="space-y-1">
                                            <p className="text-gray-500 font-semibold uppercase">Recovery:</p>
                                            <ul className="list-disc pl-4 text-gray-300">
                                                {item.critical_recovery_steps.slice(0, 3).map((step: any) => (
                                                    <li key={step.step}>{step.action}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Training Curriculum Section */}
                <div className="page-break">
                    <h3 className="text-xl font-bold text-brand-blue mb-6 border-b border-dark-border pb-2">III. Training Curriculum Overview</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {trainingCourses.map(course => (
                            <div key={course.id} className="p-4 border border-dark-border rounded-lg bg-dark-input/30">
                                <p className="text-xs font-bold text-brand-green mb-1">{course.level}</p>
                                <h4 className="font-bold text-white mb-2">{course.title}</h4>
                                <p className="text-sm text-gray-400">{course.description}</p>
                                <p className="text-xs text-brand-blue mt-2">{course.modules.length} Modules / {course.modules.reduce((acc, m) => acc + m.topics.length, 0)} Topics</p>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Blueprint Section */}
                <div className="page-break">
                    <h3 className="text-xl font-bold text-brand-blue mb-6 border-b border-dark-border pb-2">IV. Technical Diagram Index</h3>
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
                        {[...blueprints.megajet, ...blueprints.grassilli].map(bp => (
                            <div key={bp.id} className="text-center">
                                <div className="h-32 bg-dark-bg rounded border border-dark-border overflow-hidden mb-2">
                                    <img src={bp.imageData} alt={bp.name} className="w-full h-full object-cover" />
                                </div>
                                <p className="text-[10px] text-gray-400 truncate">{bp.name}</p>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Recent Logs Section */}
                <div className="page-break">
                    <h3 className="text-xl font-bold text-brand-blue mb-6 border-b border-dark-border pb-2">V. Recent Troubleshooting History</h3>
                    <div className="overflow-x-auto">
                        <table className="min-w-full text-[10px] text-left">
                            <thead className="bg-dark-bg text-gray-500 uppercase">
                                <tr>
                                    <th className="p-2 border border-dark-border">Date</th>
                                    <th className="p-2 border border-dark-border">System</th>
                                    <th className="p-2 border border-dark-border">Issue</th>
                                    <th className="p-2 border border-dark-border">Recovery</th>
                                    <th className="p-2 border border-dark-border">By</th>
                                </tr>
                            </thead>
                            <tbody>
                                {logEntries.slice(0, 30).map(log => (
                                    <tr key={log.id} className="border-b border-dark-border">
                                        <td className="p-2 border border-dark-border whitespace-nowrap">{new Date(log.timestamp).toLocaleDateString()}</td>
                                        <td className="p-2 border border-dark-border">{log.system} ({log.equipmentId})</td>
                                        <td className="p-2 border border-dark-border font-semibold">{log.issue}</td>
                                        <td className="p-2 border border-dark-border">{log.recoverySteps.substring(0, 80)}...</td>
                                        <td className="p-2 border border-dark-border capitalize">{log.author}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>

                {/* Footer */}
                <div className="text-center pt-10 border-t border-dark-border text-xs text-gray-500 italic">
                    <p>END OF DOCUMENT - CONFIDENTIAL FOR INTERNAL USE ONLY AT PECOFOODS POCHANATAS FACILITY</p>
                    <p>© {new Date().getFullYear()} PecoFoods Industrial AI Suite</p>
                </div>
            </div>
        </div>
    );
};

