import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Login from './components/Login';
import ChatInterface from './components/ChatInterface';

import { User, LogEntry, System, ChatMessage, TroubleshootingScenario, Blueprint, TrainingCourse, ShiftReport } from './types';
import { PECOFOODS_KNOWLEDGE_BASE } from './constants/megajetKnowledge';
import { EQUIPMENT_IDS } from './constants';
import { initialTrainingCourses } from './data/trainingCourses';
import { initialMegajetBlueprints, initialGrasselliBlueprints } from './data/initialDiagrams';


const MAX_CHAT_HISTORY = 50; // Keep the last 50 messages

const prePopulateLogs = (): LogEntry[] => {
    const troubleshootingEntries = PECOFOODS_KNOWLEDGE_BASE.filter(item => item.type === 'troubleshooting');

    return troubleshootingEntries.map((item: any, index) => {
        const systemString = item.affected_system?.split(' - ')[0];
        const system = systemString === 'Megajet' ? System.Megajet : System.Grassilli;

        const recoverySteps = (item.critical_recovery_steps as any[])
            ?.map(step => `${step.step}. ${step.action}`)
            .join('\n') || '';

        return {
            id: `kb-log-${item.id}`,
            timestamp: new Date(Date.now() - (index + 1) * 24 * 60 * 60 * 1000).toISOString(),
            system: system,
            equipmentId: EQUIPMENT_IDS[system][0] || 'N/A',
            issue: item.title,
            symptoms: (item.symptoms as string[])?.join(', ') || '',
            possibleCauses: (item.likely_causes as string[])?.join(', ') || '',
            recoverySteps: recoverySteps,
            author: 'brett'
        };
    }).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
};

const createEmptyReport = (user?: Omit<User, 'password'>): ShiftReport => ({
    id: `shift-${Date.now()}`,
    date: new Date().toISOString().split('T')[0],
    shift: 'Night',
    operator: user?.username || '',
    hourlyReadings: Array.from({ length: 12 }, (_, i) => ({
        hour: `${i + 1}:00`,
        product: '',
        avgWeight: '',
        avgThickness: '',
        density: '',
        corrections: '',
        delfix: ''
    })),
    downtimeEvents: [],
    beltSpeedChecks: [
        { id: '1', time: '', product: '', speed: '', type: 'Routine' },
        { id: '2', time: '', product: '', speed: '', type: 'Routine' },
        { id: '3', time: '', product: '', speed: '', type: 'Routine' }
    ]
});

const App: React.FC = () => {
  const [user, setUser] = useState<Omit<User, 'password'> | null>(null);

  const [logEntries, setLogEntries] = useState<LogEntry[]>(() => {
    const savedLogs = localStorage.getItem('pecofoods-logs');
    if (savedLogs) {
        try {
            return JSON.parse(savedLogs);
        } catch (e) {
            console.error("Failed to parse logs from localStorage", e);
            const initialLogs = prePopulateLogs();
            localStorage.setItem('pecofoods-logs', JSON.stringify(initialLogs));
            return initialLogs;
        }
    }
    const initialLogs = prePopulateLogs();
    localStorage.setItem('pecofoods-logs', JSON.stringify(initialLogs));
    return initialLogs;
  });

  const [chatHistory, setChatHistory] = useState<ChatMessage[]>(() => {
    const savedHistory = localStorage.getItem('pecofoods-chat-history');
    if (savedHistory) {
      try {
        return JSON.parse(savedHistory);
      } catch (e) {
        console.error("Failed to parse chat history from localStorage", e);
      }
    }
    return [
      {
        id: `model-init-${Date.now()}`,
        role: 'model',
        text: "Welcome to Active Recovery. I have complete knowledge of the Megajet and Grasselli systems for poultry processing. Describe your issue or upload a photo, and I'll provide step-by-step guidance. All conversations are shared to improve my responses for everyone."
      }
    ];
  });

  const [troubleshootingScenarios, setTroubleshootingScenarios] = useState<TroubleshootingScenario[]>(() => {
    const savedScenarios = localStorage.getItem('pecofoods-scenarios');
    if (savedScenarios) {
      try {
        return JSON.parse(savedScenarios);
      } catch (e) {
        console.error("Failed to parse scenarios from localStorage", e);
        return [];
      }
    }
    return [];
  });

  const [trainingCourses, setTrainingCourses] = useState<TrainingCourse[]>(() => {
    const savedCourses = localStorage.getItem('pecofoods-training-courses');
    if (savedCourses) {
        try {
            return JSON.parse(savedCourses);
        } catch (e) {
            console.error("Failed to parse training courses from localStorage", e);
            return initialTrainingCourses;
        }
    }
    return initialTrainingCourses;
  });

  const [blueprints, setBlueprints] = useState<{ megajet: Blueprint[], grassilli: Blueprint[] }>(() => {
    const savedBlueprints = localStorage.getItem('pecofoods-blueprints');
    if (savedBlueprints) {
      try {
        const parsed = JSON.parse(savedBlueprints);
        // Basic validation to ensure it has the expected structure
        if (parsed.megajet && parsed.grassilli) {
            return parsed;
        }
      } catch (e) {
        console.error("Failed to parse blueprints from localStorage", e);
      }
    }
    return {
        megajet: initialMegajetBlueprints,
        grassilli: initialGrasselliBlueprints
    };
  });

  const [currentShiftReport, setCurrentShiftReport] = useState<ShiftReport>(() => {
    const savedReport = localStorage.getItem('pecofoods-current-shift');
    if (savedReport) {
      try {
        return JSON.parse(savedReport);
      } catch (e) {
        console.error("Failed to parse shift report", e);
      }
    }
    return createEmptyReport();
  });

  useEffect(() => {
    localStorage.setItem('pecofoods-training-courses', JSON.stringify(trainingCourses));
  }, [trainingCourses]);

  useEffect(() => {
    localStorage.setItem('pecofoods-blueprints', JSON.stringify(blueprints));
  }, [blueprints]);

  useEffect(() => {
    localStorage.setItem('pecofoods-scenarios', JSON.stringify(troubleshootingScenarios));
  }, [troubleshootingScenarios]);

  useEffect(() => {
    localStorage.setItem('pecofoods-current-shift', JSON.stringify(currentShiftReport));
  }, [currentShiftReport]);

  useEffect(() => {
    // Prune history if it's too long
    if (chatHistory.length > MAX_CHAT_HISTORY) {
        const prunedHistory = chatHistory.slice(chatHistory.length - MAX_CHAT_HISTORY);
        localStorage.setItem('pecofoods-chat-history', JSON.stringify(prunedHistory));
    } else {
        localStorage.setItem('pecofoods-chat-history', JSON.stringify(chatHistory));
    }
  }, [chatHistory]);

  useEffect(() => {
    localStorage.setItem('pecofoods-logs', JSON.stringify(logEntries));
  }, [logEntries]);

  useEffect(() => {
    const savedUserJson = sessionStorage.getItem('pecofoods-user');
    if (savedUserJson) {
      try {
        const savedUser = JSON.parse(savedUserJson);
        setUser(savedUser);
        // If report operator is empty, set it
        setCurrentShiftReport(prev => prev.operator ? prev : { ...prev, operator: savedUser.username });
      } catch (error)
      {
        console.error("Failed to parse user from sessionStorage", error);
        sessionStorage.removeItem('pecofoods-user');
      }
    }
  }, []);

  const handleLogin = (loggedInUser: Omit<User, 'password'>) => {
    setUser(loggedInUser);
    sessionStorage.setItem('pecofoods-user', JSON.stringify(loggedInUser));
    setCurrentShiftReport(prev => ({ ...prev, operator: loggedInUser.username }));
  };

  const handleLogout = () => {
    setUser(null);
    sessionStorage.removeItem('pecofoods-user');
  };

  const addLogEntry = (entry: Omit<LogEntry, 'id' | 'timestamp' | 'author'>) => {
    if (!user) return; // Should not happen if user is logged in
    const newEntry: LogEntry = {
        ...entry,
        id: `log-${Date.now()}`,
        timestamp: new Date().toISOString(),
        author: user.username,
    };
    setLogEntries(prev => [newEntry, ...prev]);
  };

  const updateLogEntry = (updatedEntry: LogEntry) => {
    setLogEntries(prev => prev.map(entry => entry.id === updatedEntry.id ? updatedEntry : entry));
  };

  const deleteLogEntry = (id: string) => {
    if (window.confirm('Are you sure you want to delete this log entry? This action cannot be undone.')) {
        setLogEntries(prev => prev.filter(entry => entry.id !== id));
    }
  };

  const addTroubleshootingScenario = (scenario: Omit<TroubleshootingScenario, 'id'>) => {
    const newScenario: TroubleshootingScenario = {
        ...scenario,
        id: `scenario-${Date.now()}`,
    };
    setTroubleshootingScenarios(prev => [newScenario, ...prev]);
  };

  const addTrainingCourse = (course: Omit<TrainingCourse, 'id'>) => {
    const newCourse: TrainingCourse = {
        ...course,
        id: `course-${Date.now()}`,
    };
    setTrainingCourses(prev => [newCourse, ...prev]);
    return newCourse;
  };

  const addBlueprint = (blueprint: Omit<Blueprint, 'id'>, system: System) => {
    const newBlueprint: Blueprint = {
      ...blueprint,
      id: `blueprint-${Date.now()}`,
    };
    const systemKey = system.toLowerCase() as keyof typeof blueprints;
    setBlueprints(prev => ({
        ...prev,
        [systemKey]: [newBlueprint, ...prev[systemKey]]
    }));
  };

  const deleteBlueprint = (id: string, system: System) => {
    if (window.confirm('Are you sure you want to delete this blueprint? This action cannot be undone.')) {
        const systemKey = system.toLowerCase() as keyof typeof blueprints;
        setBlueprints(prev => ({
            ...prev,
            [systemKey]: prev[systemKey].filter(d => d.id !== id)
        }));
    }
  };

  const updateShiftReport = (report: ShiftReport) => {
    setCurrentShiftReport(report);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-dark-bg text-dark-text font-sans flex flex-col h-screen overflow-hidden">
        <Header user={user} onLogout={handleLogout} />
        <main className="flex-1 flex flex-col min-h-0">
            <ChatInterface
              user={user}
              logEntries={logEntries}
              addLogEntry={addLogEntry}
              updateLogEntry={updateLogEntry}
              deleteLogEntry={deleteLogEntry}
              chatHistory={chatHistory}
              setChatHistory={setChatHistory}
              troubleshootingScenarios={troubleshootingScenarios}
              addTroubleshootingScenario={addTroubleshootingScenario}
              trainingCourses={trainingCourses}
              addTrainingCourse={addTrainingCourse}
              blueprints={blueprints}
              addBlueprint={addBlueprint}
              deleteBlueprint={deleteBlueprint}
              currentShiftReport={currentShiftReport}
              updateShiftReport={updateShiftReport}
            />
        </main>
    </div>
  );
};

export default App;

