                    <div>
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="text-lg font-bold text-brand-blue border-l-4 border-brand-blue pl-3">Belt Speed & Changeovers</h3>
                            <button onClick={addBeltCheck} className="no-print text-brand-blue hover:text-blue-400"><PlusCircleIcon className="h-6 w-6" /></button>
                        </div>
                        <table className="min-w-full text-sm">
                            <thead className="bg-dark-bg text-gray-400 uppercase text-[10px]">
                                <tr>
                                    <th className="p-2 border border-dark-border w-20">Time</th>
                                    <th className="p-2 border border-dark-border">Product</th>
                                    <th className="p-2 border border-dark-border w-24">Speed (m/min)</th>
                                    <th className="p-2 border border-dark-border w-28">Type</th>
                                    <th className="p-1 border border-dark-border no-print w-10"></th>
                                </tr>
                            </thead>
                            <tbody>
                                {report.beltSpeedChecks.map((check) => (
                                    <tr key={check.id} className="border-b border-dark-border">
                                        <td className="p-1 border border-dark-border"><input type="text" value={check.time} onChange={e => handleBeltCheckChange(check.id, 'time', e.target.value)} className={inputClass} placeholder="21:30" /></td>
                                        <td className="p-1 border border-dark-border"><input type="text" value={check.product} onChange={e => handleBeltCheckChange(check.id, 'product', e.target.value)} className={inputClass} /></td>
                                        <td className="p-1 border border-dark-border"><input type="text" value={check.speed} onChange={e => handleBeltCheckChange(check.id, 'speed', e.target.value)} className={inputClass} /></td>
                                        <td className="p-1 border border-dark-border">
                                            <select value={check.type} onChange={e => handleBeltCheckChange(check.id, 'type', e.target.value)} className={inputClass}>
                                                <option value="Routine">Routine</option>
                                                <option value="Changeover">Changeover</option>
                                            </select>
                                        </td>
                                        <td className="p-1 border border-dark-border no-print text-center">
                                            <button onClick={() => removeBeltCheck(check.id)} className="text-red-500"><TrashIcon className="h-4 w-4" /></button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>

                    {/* Downtime Tracking */}
                    <div>
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="text-lg font-bold text-brand-blue border-l-4 border-brand-blue pl-3">Megajet Downtime Log</h3>
                            <button onClick={addDowntimeEvent} className="no-print text-brand-blue hover:text-blue-400"><PlusCircleIcon className="h-6 w-6" /></button>
                        </div>
                        <table className="min-w-full text-sm">
                            <thead className="bg-dark-bg text-gray-400 uppercase text-[10px]">
                                <tr>
                                    <th className="p-2 border border-dark-border w-20">Start</th>
                                    <th className="p-2 border border-dark-border w-20">End</th>
                                    <th className="p-2 border border-dark-border w-20">Unit #</th>
                                    <th className="p-2 border border-dark-border">Reason / Root Cause</th>
                                    <th className="p-1 border border-dark-border no-print w-10"></th>
                                </tr>
                            </thead>
                            <tbody>
                                {report.downtimeEvents.map((event) => (
                                    <tr key={event.id} className="border-b border-dark-border">
                                        <td className="p-1 border border-dark-border"><input type="text" value={event.startTime} onChange={e => handleDowntimeChange(event.id, 'startTime', e.target.value)} className={inputClass} /></td>
                                        <td className="p-1 border border-dark-border"><input type="text" value={event.endTime} onChange={e => handleDowntimeChange(event.id, 'endTime', e.target.value)} className={inputClass} /></td>
                                        <td className="p-1 border border-dark-border"><input type="text" value={event.unit} onChange={e => handleDowntimeChange(event.id, 'unit', e.target.value)} className={inputClass} /></td>
                                        <td className="p-1 border border-dark-border"><input type="text" value={event.reason} onChange={e => handleDowntimeChange(event.id, 'reason', e.target.value)} className={inputClass} /></td>
                                        <td className="p-1 border border-dark-border no-print text-center">
                                            <button onClick={() => removeDowntimeEvent(event.id)} className="text-red-500"><TrashIcon className="h-4 w-4" /></button>
                                        </td>
                                    </tr>
                                ))}
                                {report.downtimeEvents.length === 0 && (
                                    <tr>
                                        <td colSpan={5} className="p-4 text-center text-gray-500 italic">No downtime recorded this shift.</td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>

                {/* Verification Footer */}
                <div className="grid grid-cols-2 gap-8 pt-10 border-t border-dark-border">
                    <div className="space-y-4">
                        <div className="border-b border-gray-600 h-10 flex items-end">
                            <span className="text-xs text-gray-500 uppercase font-bold mr-2">Operator Signature:</span>
                        </div>
                        <div className="border-b border-gray-600 h-10 flex items-end">
                            <span className="text-xs text-gray-500 uppercase font-bold mr-2">Supervisor Signature:</span>
                        </div>
                    </div>
                    <div className="bg-dark-input/20 p-4 rounded text-xs text-gray-400 italic">
                        <p>Internal Quality Control: This report must be completed hourly and turned in at the end of the shift. All deviations from target weight beyond +/- 5g must be documented in the 'Corrections' column.</p>
                        <p className="mt-2">© {new Date().getFullYear()} PecoFoods Industrial Intelligence</p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ShiftReportForm;
